def _extract_function(task_text):
    """
    Извлекает математическую функцию из текста задания ЕГЭ.
    Корректно обрабатывает: ln(...), sin(...), cos(...), e^..., x², x³, √(...), 1/x
    А также сложные выражения вида: y = 8*ln(x+7) - 8x + 3
    """
    # Очищаем от HTML и LaTeX
    clean = re.sub(r'<[^>]+>', '', task_text)
    clean = clean.replace('\\(', '').replace('\\)', '')
    clean = clean.replace('\\[', '').replace('\\]', '')
    clean = clean.replace('{', '').replace('}', '')
    clean = clean.replace('cdot', '*')
    clean = clean.replace('left', '').replace('right', '')
    clean = clean.replace('минус', '-')
    clean = clean.replace('плюс', '+')
    
    # Ищем "y = ..." — это самый надёжный способ
    y_match = re.search(r'y\s*=\s*(.+?)(?:\\|на\s|\.|\n|$)', clean)
    if y_match:
        func = y_match.group(1).strip()
        # Очищаем от оставшегося LaTeX
        func = func.replace('\\', '')
        func = re.sub(r'\([^)]*\)\^2', lambda m: f'({m.group(0)[1:-3]})^2', func)  # (x+4)² -> (x+4)^2
        func = func.replace('^', '^').replace('**', '^')
        func = func.replace(' ', '')
        # Заменяем ln на log (GeoGebra понимает и так)
        func = func.replace('ln', 'ln')
        if func and len(func) > 1:
            return func
    
    # Если "y =" не найден, ищем по ключевым функциям
    # ln(выражение) с коэффициентом
    ln_match = re.search(r'(\d*)\s*\\?ln\s*\(([^)]+)\)', task_text)
    if ln_match:
        coef = ln_match.group(1) or ''
        inner = ln_match.group(2).replace(' ', '')
        return f"{coef}*ln({inner})"
    
    # sin(выражение)
    sin_match = re.search(r'(\d*)\s*\\?sin\s*\(?([^)]+)\)?', task_text)
    if sin_match:
        coef = sin_match.group(1) or '1'
        inner = sin_match.group(2).replace(' ', '')
        return f"{coef}*sin({inner})" if coef != '1' else f"sin({inner})"
    
    # cos(выражение)
    cos_match = re.search(r'(\d*)\s*\\?cos\s*\(?([^)]+)\)?', task_text)
    if cos_match:
        coef = cos_match.group(1) or '1'
        inner = cos_match.group(2).replace(' ', '')
        return f"{coef}*cos({inner})" if coef != '1' else f"cos({inner})"
    
    # e^x
    if re.search(r'e\^|\\exp', task_text):
        return "e^x"
    
    # x²
    if re.search(r'x\^2|x²|квадрат', task_text):
        return "x^2"
    
    # x³
    if re.search(r'x\^3|x³|куб', task_text):
        return "x^3"
    
    # √x
    sqrt_match = re.search(r'\\?sqrt\{?([^}]+)\}?', task_text)
    if sqrt_match:
        inner = sqrt_match.group(1).replace(' ', '')
        return f"sqrt({inner})"
    
    # 1/x
    if re.search(r'1/x|обратн', task_text):
        return "1/x"
    
    return None


def _get_graphic_for_task(task_num, task_text):
    """Возвращает URL GeoGebra для графика по тексту задачи, если задача относится к графикам."""
    if task_num not in [6, 9, 11]:
        return None
    
    func = _extract_function(task_text)
    if not func:
        return None
    
    encoded = urllib.parse.quote(func)
    return (
        f"https://www.geogebra.org/graphing"
        f"?command=f(x)={encoded}"
        f"&showToolBar=false&showAlgebraInput=false&showMenuBar=false"
        f"&showResetIcon=false&appName=graphing&language=ru"
    )


def _fetch_real_problem(problem_id):
    try:
        from sdamgia import SdamGIA
        client = SdamGIA()
        problem = client.get_problem_by_id('math', problem_id)
        if not problem or not problem.get('text'):
            return None
        return {
            "topic": problem.get('topic', 'Задача'),
            "text": problem.get('text', ''),
            "answer": str(problem.get('answer', '')).strip()
        }
    except:
        return None


def _try_load_from_sdamgia(num):
    try:
        from sdamgia import SdamGIA
        client = SdamGIA()
        ids = client.search('math', f"Задание {num}")
        if not ids:
            ids = client.search('math', f"Тип {num}")
        if ids:
            for _ in range(3):
                problem_id = random.choice(ids)
                problem = _fetch_real_problem(problem_id)
                if problem and problem['text']:
                    return {
                        "sdamgia_id": f"sdamgia_{problem_id}",
                        "topic": problem['topic'],
                        "text": problem['text'],
                        "answer": problem['answer'],
                        "difficulty": 2 if num > 12 else 1,
                        "tags": ["с РешуЕГЭ"],
                        "part": 1 if num <= 12 else 2
                    }
    except:
        pass
    return None


def _get_task_for_number(num: int):
    if num in TASKS_BANK and TASKS_BANK[num]:
        task_data = random.choice(TASKS_BANK[num])
        return {
            "sdamgia_id": f"local_{num}_{random.randint(10000, 99999)}",
            "topic": task_data["topic"],
            "text": task_data["text"],
            "answer": task_data["answer"],
            "difficulty": 2 if num > 12 else 1,
            "tags": ["реальное задание ЕГЭ"],
            "part": 1 if num <= 12 else 2
        }
    return {
        "sdamgia_id": f"local_{num}",
        "topic": f"Задание типа {num}",
        "text": f"<p>Задание типа {num}.</p>",
        "answer": "0",
        "difficulty": 1,
        "tags": ["заглушка"],
        "part": 1 if num <= 12 else 2
    }


class SdamGiaService:
    def __init__(self):
        pass

    async def fetch_and_cache_tasks(self, db: AsyncSession, numbers: list) -> list:
        repo = TaskRepository(db)
        tasks = []
        
        for num in numbers:
            real_task = _try_load_from_sdamgia(num)
            
            if real_task:
                task = await repo.create_task(**real_task)
                tasks.append(task)
                continue
            
            task_data = _get_task_for_number(num)
            task = await repo.create_task(**task_data)
            tasks.append(task)
        
        return tasks